export const Invoice_applyPayment = mutation({
  args: {
    docId: v.id("invoices"),
    paymentAmount: v.number(),
    paymentId: v.string()
  },
  handler: async (ctx, { docId, paymentAmount, paymentId }) => {
    const user = await resolveMutationAuth(ctx);
    const doc = await ctx.db.get(docId) as Record<string, any> | null;
    if (!doc) throw new Error("Invoice not found");
    if (!(["finance", "finance_manager", "manager", "admin"].includes(user.role))) throw new Error("Invoice management");
    if (!(["SENT", "VIEWED", "OVERDUE", "PARTIALLY_PAID"].includes(doc.status))) throw new Error("Guard 0 failed");
    if (!((paymentAmount > 0))) throw new Error("Guard 1 failed");
    if (!((paymentAmount <= doc.amountDue))) throw new Error("Guard 2 failed");
    const updates = {
      amountPaid: (doc.amountPaid + paymentAmount),
      amountDue: (doc.amountDue - paymentAmount),
      status: "PARTIALLY_PAID"
    };
    await ctx.db.patch(docId, updates as any);
    const payload: Record<string, any> = { id: docId, ...doc, ...updates, result: { id: docId, ...doc, ...updates }, _subject: { entity: "Invoice", command: "applyPayment", id: docId } };
    await ctx.db.insert("manifestEvents", { type: "PaymentApplied", entity: "Invoice", entityId: docId, payload: {}, createdAt: Date.now() });
    return { ...doc, ...updates };
  },
});

